mapper.sql:
s.status = 'ACTIVE' AND u.deleted_at IS NULL AND t.deleted_at IS NULL AND ( u.user_type = 'SYSTEM_OPS' OR t.admin_user_id = u.id )
AND u.tenant_id = #{currentTenantId}
AND ( u.username LIKE CONCAT('%', #{query.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{query.keyword}, '%') OR COALESCE(t.display_name, t.name, t.code) LIKE CONCAT('%', #{query.keyword}, '%') OR s.login_ip LIKE CONCAT('%', #{query.keyword}, '%') )
AND s.platform = #{query.platform}
AND u.user_type = 'SYSTEM_OPS'
AND u.user_type <> 'SYSTEM_OPS' AND t.admin_user_id = u.id

mapper.select:
SELECT u.id AS userId, u.tenant_id AS tenantId, u.username FROM users u JOIN tenants t ON t.id = u.tenant_id WHERE u.username = #{username} AND u.deleted_at IS NULL AND t.deleted_at IS NULL AND ( u.user_type = 'SYSTEM_OPS' OR t.admin_user_id = u.id )
AND u.tenant_id = #{currentTenantId}
LIMIT 1
